=<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Welcome to Laundrofast</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600&family=Syne:wght@700;800&display=swap');

    * { margin: 0; padding: 0; box-sizing: border-box; }

    body {
      background-color: #e8f0fe;
      font-family: 'DM Sans', sans-serif;
      padding: 40px 20px;
    }

    .email-wrapper {
      max-width: 600px;
      margin: 0 auto;
      background: #ffffff;
      border-radius: 20px;
      overflow: hidden;
      box-shadow: 0 8px 40px rgba(26, 86, 219, 0.12);
    }

    /* ── HEADER ── */
    .header {
      background: linear-gradient(135deg, #1a56db 0%, #1e40af 60%, #1d4ed8 100%);
      padding: 44px 40px 36px;
      position: relative;
      overflow: hidden;
    }

    .header::before {
      content: '';
      position: absolute;
      top: -60px; right: -60px;
      width: 220px; height: 220px;
      border-radius: 50%;
      background: rgba(255,255,255,0.07);
    }

    .header::after {
      content: '';
      position: absolute;
      bottom: -80px; left: -40px;
      width: 260px; height: 260px;
      border-radius: 50%;
      background: rgba(255,255,255,0.05);
    }

    .logo-row {
      display: flex;
      align-items: center;
      gap: 10px;
      margin-bottom: 28px;
    }

    .logo-icon {
      width: 38px; height: 38px;
      background: rgba(255,255,255,0.2);
      border-radius: 10px;
      display: flex; align-items: center; justify-content: center;
      font-size: 20px;
    }

    .logo-text {
      font-family: 'Syne', sans-serif;
      font-weight: 800;
      font-size: 22px;
      color: #ffffff;
      letter-spacing: -0.5px;
    }

    .header h1 {
      font-family: 'Syne', sans-serif;
      font-weight: 800;
      font-size: 34px;
      color: #ffffff;
      line-height: 1.15;
      letter-spacing: -0.8px;
      position: relative;
      z-index: 1;
    }

    .header h1 span {
      color: #93c5fd;
    }

    .header-sub {
      margin-top: 10px;
      font-size: 15px;
      color: rgba(255,255,255,0.78);
      position: relative;
      z-index: 1;
    }

    /* ── WAVE DIVIDER ── */
    .wave {
      display: block;
      width: 100%;
      background: #1a56db;
      line-height: 0;
    }
    .wave svg {
      display: block;
      width: 100%;
    }

    /* ── BODY ── */
    .body {
      padding: 36px 40px 20px;
    }

    .greeting {
      font-size: 17px;
      color: #1e293b;
      line-height: 1.6;
      margin-bottom: 24px;
    }

    .greeting strong {
      color: #1a56db;
      font-weight: 600;
    }

    /* ── PLAN CARD ── */
    .plan-card {
      background: #f0f5ff;
      border: 1.5px solid #bfdbfe;
      border-radius: 14px;
      padding: 24px 28px;
      margin-bottom: 28px;
    }

    .plan-card-label {
      font-size: 11px;
      font-weight: 600;
      letter-spacing: 1.2px;
      text-transform: uppercase;
      color: #6b7280;
      margin-bottom: 10px;
    }

    .plan-card-title {
      font-family: 'Syne', sans-serif;
      font-size: 24px;
      font-weight: 700;
      color: #1a56db;
      margin-bottom: 4px;
    }

    .plan-card-type {
      font-size: 14px;
      color: #64748b;
      margin-bottom: 16px;
    }

    .plan-features {
      list-style: none;
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 12px 16px;
    }

    .plan-features li {
      display: flex;
      align-items: flex-start;
      gap: 10px;
      font-size: 14px;
      color: #374151;
      line-height: 1.5;
    }

    .check {
      width: 20px; height: 20px;
      background: #1a56db;
      border-radius: 50%;
      display: flex; align-items: center; justify-content: center;
      flex-shrink: 0;
      color: white;
      font-size: 11px;
    }

    /* ── NEXT STEPS ── */
    .steps-title {
      font-family: 'Syne', sans-serif;
      font-weight: 700;
      font-size: 18px;
      color: #0f172a;
      margin-bottom: 16px;
    }

    .steps {
      display: flex;
      flex-direction: column;
      gap: 14px;
      margin-bottom: 32px;
    }

    .step {
      display: flex;
      align-items: flex-start;
      gap: 14px;
    }

    .step-num {
      width: 32px; height: 32px;
      min-width: 32px;
      background: #1a56db;
      color: #fff;
      font-family: 'Syne', sans-serif;
      font-weight: 700;
      font-size: 14px;
      border-radius: 8px;
      display: flex; align-items: center; justify-content: center;
      flex-shrink: 0;
      margin-top: 2px;
    }

    .step-text {
      flex: 1;
    }

    .step-text strong {
      display: block;
      font-size: 15px;
      font-weight: 600;
      color: #0f172a;
      margin-bottom: 4px;
      line-height: 1.4;
    }

    .step-text span {
      display: block;
      font-size: 13.5px;
      color: #6b7280;
      line-height: 1.6;
    }

    /* ── CTA ── */
    .cta-wrapper {
      text-align: center;
      margin-bottom: 32px;
    }

    .cta-btn {
      display: inline-block;
      background: linear-gradient(135deg, #1a56db, #1d4ed8);
      color: #ffffff !important;
      text-decoration: none;
      font-family: 'Syne', sans-serif;
      font-weight: 700;
      font-size: 15px;
      letter-spacing: 0.3px;
      padding: 16px 44px;
      border-radius: 12px;
      box-shadow: 0 4px 20px rgba(26, 86, 219, 0.35);
    }

    /* ── DIVIDER ── */
    .divider {
      height: 1px;
      background: #e2e8f0;
      margin: 0 40px 28px;
    }

    /* ── FOOTER ── */
    .footer {
      background: #f8faff;
      padding: 24px 40px 32px;
      border-top: 1px solid #e2e8f0;
    }

    .footer-logo {
      font-family: 'Syne', sans-serif;
      font-weight: 800;
      font-size: 16px;
      color: #1a56db;
      margin-bottom: 8px;
    }

    .footer p {
      font-size: 12.5px;
      color: #94a3b8;
      line-height: 1.6;
    }

    .footer a {
      color: #1a56db;
      text-decoration: none;
    }

    .social-row {
      display: flex;
      gap: 10px;
      margin-top: 14px;
    }

    .social-btn {
      width: 34px; height: 34px;
      background: #e0eaff;
      border-radius: 8px;
      display: flex; align-items: center; justify-content: center;
      font-size: 15px;
      text-decoration: none;
    }

    /* ── MOBILE RESPONSIVE ── */
    @media only screen and (max-width: 600px) {
      body {
        padding: 20px 10px;
      }

      .email-wrapper {
        border-radius: 12px;
      }

      .header {
        padding: 32px 24px 28px;
      }

      .header h1 {
        font-size: 28px;
      }

      .body {
        padding: 28px 24px 16px;
      }

      .plan-card {
        padding: 20px;
      }

      .plan-features {
        grid-template-columns: 1fr;
        gap: 10px;
      }

      .steps {
        gap: 18px;
      }

      .cta-btn {
        font-size: 14px;
        padding: 14px 36px;
      }

      .footer {
        padding: 20px 24px 28px;
      }

      .divider {
        margin: 0 24px 24px;
      }
    }
  </style>
</head>
